import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Sanitize and escape user input to prevent XSS
        String safeUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handling user input by including it as text in the HTML response
        String outputHtml = "<html><body>Welcome, " + safeUserInput + "</body></html>";

        // Output the HTML response
        System.out.println(outputHtml);
    }
}

